import React, { Component } from "react";
import { Link } from "gatsby";

import { NavigationDrawer, Button }  from "react-md";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";

import "./NavBar.scss"

function getNavItems(config) {
  const NavItems = [
    {
      primaryText: "Home",
      leftIcon: <FontAwesomeIcon icon="home" color="white" size="lg" />, 
      component: Link,
      to: "/",
    },
    {
      divider: true
    },
    {
      primaryText: "Blog",
      leftIcon: <FontAwesomeIcon icon="blog" color="white" size="lg" />, 
      component: Link,
      to: "/",
    },
    {
      divider: true
    },
  ];
  
  if (config.socialLinks) {
    config.socialLinks.forEach(link => {
      NavItems.push({
        primaryText: link.label,
        leftIcon: <FontAwesomeIcon 
          color="white" 
          icon={link.iconClassName} 
          size="lg"/>,
        component: "a",
        href: link.url,
      });
    });

  }
  return NavItems;
}

export default class NavBar extends Component{
  render () {
    const { bodyChildren, config } = this.props;
    console.log(bodyChildren);
    return (
      <NavigationDrawer
        drawerTitle={config.title}
        toolbarTitle="Amperture"
        toolbarActions={<Button icon onClick={this.hide}>close</Button>}
        navItems={getNavItems(config)}
        mobileDrawerType={NavigationDrawer.DrawerTypes.TEMPORARY_MINI}
        tabletDrawerType={NavigationDrawer.DrawerTypes.PERSISTENT_MINI}
        desktopDrawerType={NavigationDrawer.DrawerTypes.PERSISTENT_MINI}
        contentClassName='main-container'
      >
        <div className='main-content'>
            { this.props.children }
        </div>
      </NavigationDrawer>
    );
  }
}
